const KEY="campusLifeLab10";const seed={assignments:[{id:"A-101",title:"MVP Prototype Review",course:"ICT105",studentId:"6612345678",dueDate:"2026-07-28",priority:"High",status:"In Progress"},{id:"A-102",title:"Usability Testing Report",course:"HCI201",studentId:"6612345678",dueDate:"2026-08-02",priority:"Medium",status:"Pending"},{id:"A-103",title:"System Requirements",course:"ICT105",studentId:"6612345678",dueDate:"2026-07-20",priority:"High",status:"Completed"}],projects:[{name:"Campus Life MVP",owner:"STT Team",progress:68,status:"In Progress"},{name:"Research Presentation",owner:"Sutt",progress:85,status:"Review"}],links:[{name:"Rangsit University Portal",url:"https://www.rsu.ac.th"},{name:"GitHub Repository",url:"https://github.com/Thant198/ICT105-STT-MVP"}]};let data=JSON.parse(localStorage.getItem(KEY)||"null")||seed;function save(){localStorage.setItem(KEY,JSON.stringify(data))}function mask(v){return v.length<5?"***":v.slice(0,2)+"*".repeat(v.length-4)+v.slice(-2)}function safe(v){return String(v).replace(/[&<>"']/g,c=>({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#039;"}[c]))}document.querySelectorAll('[data-view]').forEach(b=>b.onclick=()=>{document.querySelectorAll('.view').forEach(v=>v.classList.remove('active'));document.getElementById(b.dataset.view).classList.add('active');render()});function filtered(){let q=(search.value||'').toLowerCase(),s=statusFilter.value;return data.assignments.filter(a=>(a.title+a.course).toLowerCase().includes(q)&&(s==='All'||a.status===s))}function render(){total.textContent=data.assignments.length;pending.textContent=data.assignments.filter(a=>a.status!=='Completed').length;completed.textContent=data.assignments.filter(a=>a.status==='Completed').length;let now=new Date(),soon=data.assignments.filter(a=>{let d=(new Date(a.dueDate)-now)/86400000;return d>=0&&d<=7&&a.status!=='Completed'});dueSoon.textContent=soon.length;upcoming.innerHTML=soon.map(a=>`<p><b>${safe(a.title)}</b> — ${a.dueDate}</p>`).join('')||'<p class="muted">No deadlines within 7 days.</p>';assignmentList.innerHTML=filtered().map(a=>`<article><div class="item-head"><div><b>${safe(a.title)}</b><p>${safe(a.course)} • ${a.dueDate} • ID ${mask(a.studentId)}</p></div><span class="badge">${a.status}</span></div><button onclick="editItem('${a.id}')">Edit</button> <button class="danger" onclick="removeItem('${a.id}')">Delete</button></article>`).join('')||'<p>No matching assignments.</p>';projectList.innerHTML=data.projects.map(p=>`<article><b>${p.name}</b><p>${p.owner} • ${p.status}</p><progress max="100" value="${p.progress}"></progress> ${p.progress}%</article>`).join('');linkList.innerHTML=data.links.map(l=>`<article><a href="${l.url}" target="_blank" rel="noopener"><b>${l.name}</b></a></article>`).join('');adminTable.innerHTML=data.assignments.map(a=>`<article><b>${a.id}: ${safe(a.title)}</b><p>${mask(a.studentId)} • ${a.status}</p></article>`).join('')}assignmentForm.onsubmit=e=>{e.preventDefault();if(!/^\d{8,12}$/.test(studentId.value)){formMsg.textContent='Student ID must contain 8–12 digits.';return}data.assignments.push({id:'A-'+Date.now().toString().slice(-5),title:title.value.trim(),course:course.value.trim().toUpperCase(),studentId:studentId.value,dueDate:dueDate.value,priority:priority.value,status:'Pending'});save();e.target.reset();formMsg.textContent='Assignment saved successfully.';render()};search.oninput=render;statusFilter.onchange=render;window.removeItem=id=>{if(confirm('Delete this assignment?')){data.assignments=data.assignments.filter(a=>a.id!==id);save();render()}};window.editItem=id=>{let a=data.assignments.find(x=>x.id===id),v=prompt('New title:',a.title);if(v&&v.trim().length>=3){a.title=v.trim();save();render()}};updateStatus.onclick=()=>{let a=data.assignments.find(x=>x.id.toLowerCase()===adminId.value.trim().toLowerCase());if(!a){adminMsg.textContent='Record ID not found.';return}a.status=adminStatus.value;save();adminMsg.textContent='Status updated successfully.';render()};save();render();